-- recipes-specific settings
INSERT OR IGNORE INTO `settings` (`key`, `value`, `updated_at`) VALUES ('source_title', 'My Recipes', datetime('now'));
INSERT OR IGNORE INTO `settings` (`key`, `value`, `updated_at`) VALUES ('source_description', 'A personal collection of tried-and-tested recipes', datetime('now'));
INSERT OR IGNORE INTO `settings` (`key`, `value`, `updated_at`) VALUES ('quality_guidelines', '{"keySummary":{"tips":"Use the dish name followed by the key variation or style. Keep it recognizable at a glance in a recipe grid."},"content":{"tips":"Structure every recipe with Ingredients (bulleted with quantities) and Instructions (numbered steps). Add prep/cook time and servings at the top."},"formatting":["Headings: separate Ingredients, Instructions, and Notes sections","Bullet lists: ingredients with exact quantities and units","Numbered lists: step-by-step cooking instructions in order","Bold: highlight critical temperatures, times, and visual cues","Tables: nutrition info or variation comparisons","Paragraphs: brief intro about the dish and personal notes"],"avoid":["Ingredients without quantities or units","Vague instructions like \"cook until done\"","Mixing ingredients and steps into a single block","Omitting prep time, cook time, or servings"]}', datetime('now'));
INSERT OR IGNORE INTO `settings` (`key`, `value`, `updated_at`) VALUES ('validation_limits', '{"keySummary":{"min":10,"max":150},"content":{"min":100,"max":15000},"sourceAi":{"min":1,"max":100}}', datetime('now'));

-- Site actions (recipes)
INSERT OR IGNORE INTO `site_actions` (`id`, `name`, `slug`, `description`, `fields`, `settings`, `status`, `created_at`, `updated_at`) VALUES ('5525734f-1179-485d-8707-74082f4fd541', 'Recipe Request', 'recipe-request', 'Request a recipe or suggest a dish', '[{"name":"name","type":"text","label":"Name","required":true,"placeholder":"Your name","maxLength":100},{"name":"email","type":"email","label":"Email","required":true,"placeholder":"you@example.com"},{"name":"message","type":"textarea","label":"Recipe Request","required":true,"placeholder":"What dish would you like to see a recipe for?","maxLength":2000}]', '{"success_message":"Thanks for the suggestion! We''ll consider adding that recipe.","require_honeypot":true}', 'active', '2026-03-27T01:22:54.694Z', '2026-03-27T01:22:54.694Z');
INSERT OR IGNORE INTO `site_actions` (`id`, `name`, `slug`, `description`, `fields`, `settings`, `status`, `created_at`, `updated_at`) VALUES ('d1176111-7ada-430b-8a60-ab2a3a52b010', 'Newsletter', 'newsletter', 'Get new recipes delivered to your inbox', '[{"name":"email","type":"email","label":"Email Address","required":true,"placeholder":"you@example.com"}]', '{"success_message":"You''re subscribed! New recipes will land in your inbox.","require_honeypot":true}', 'active', '2026-03-27T01:22:54.694Z', '2026-03-27T01:22:54.694Z');
